/* AESTRAT globe — textures inlined as data URIs.
   WHY: when index.html is opened directly from disk (file://), browsers refuse to
   load WebGL textures from local image files, so the globe renders blank. Data URIs
   are treated as same-origin and load everywhere — file://, GitHub Pages, any host.
   Source art lives in globe/assets/ (full-res); these are downscaled copies.
   Regenerate with the PIL script in the project notes if the art changes. */
window.AESTRAT_GLOBE_TEXTURES = {
  earth:  "data:image/jpeg;base64,",
  bump:   "data:image/jpeg;base64,",
  clouds: "data:image/png;base64,"
};
